-- Seed: initiative_templates (generated from live DB, 13 templates)
-- Regenerate after any template content change. Idempotent: upserts by id.

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  'fbf5be28-3881-4622-96e6-08f3bd2ac19c',
  'Chronic Absenteeism Reduction',
  'Attendance',
  'A tiered attendance system pairing early-warning data with relationship-based outreach: prevention for all, personalized nudges and mentoring for students sliding toward chronic absence, and barrier-removal case management for those already there.',
  'Attendance Works tiered framework; randomized trials of personalized family outreach (Rogers and Feller, 2018) showing roughly 10 percent reductions in chronic absence at very low cost; a related trial (Robinson, Lee, Dearing, and Rogers, 2018) found reductions up to 15 percent in elementary grades; early-warning indicator research showing attendance in the first month predicts year-end chronic absence; mentoring models (Success Mentors) associated with reduced absences in district evaluations. References: Rogers and Feller (2018), randomized trial of personalized absence mailings to 28,000 households, Nature Human Behaviour, roughly 10 percent reduction at roughly 6 dollars per family. Robinson, Lee, Dearing, and Rogers (2018), American Educational Research Journal. Balfanz and Byrnes (2012), chronic absence prediction research, Johns Hopkins. Attendance Works tiered framework. Evidence level: Strong for outreach nudges; Moderate for mentoring tiers.',
  ARRAY['Reduce chronic absenteeism rate', 'Improve average daily attendance', 'Strengthen family-school relationships', 'Earlier identification of attendance barriers']::text[],
  'Full year: systems and messaging in weeks 1 to 6, tiered supports running by month 2, barrier case management ongoing',
  ARRAY['Weekly attendance data export and early-warning flags', 'Staff time for outreach and mentoring (1 to 3 hours weekly per mentor)', 'Family communication tools in home languages', 'Small budget for recognition and barrier removal (alarm clocks, transit passes)']::text[],
  '[{"name": "Weekly early-warning data review", "is_core": true, "look_fors": ["Meeting happens weekly on schedule", "Every flagged student gets a named owner", "Response logged within 48 hours"], "description": "Team reviews attendance flags weekly and assigns a response within 48 hours, before absence becomes chronic.", "adaptable_boundaries": ["Meeting day and length", "Which staff attend"]}, {"name": "Positive-first family outreach", "is_core": true, "look_fors": ["Outreach references the specific student, not a form letter tone", "Contact happens before the 10 percent threshold", "Family voice captured in the log"], "description": "First contact about absence is supportive and curious, not punitive; letters and calls use personalized, plain language about days missed.", "adaptable_boundaries": ["Channel (call, text, letter, home visit)", "Language and messenger"]}, {"name": "Relationship mentor for sliding students", "is_core": true, "look_fors": ["Mentor-student pairs documented", "Weekly touchpoint logged", "Student can name their mentor"], "description": "Students at 10 to 19 percent absence get a named adult who greets them, notices absences, and checks in weekly.", "adaptable_boundaries": ["Who mentors (teachers, staff, coaches)", "Check-in format"]}, {"name": "Barrier assessment and case management", "is_core": false, "look_fors": ["Barrier named in the plan", "Concrete removal action taken"], "description": "For chronically absent students, a structured conversation identifies the actual barrier (health, transport, work, belonging) and the team removes what it can.", "adaptable_boundaries": ["Assessment tool", "Community partners used"]}, {"name": "Attendance culture and recognition", "is_core": false, "look_fors": ["Improvement recognized, not only perfection", "Messaging visible to families"], "description": "School-wide messaging that every day matters, with recognition for improved (not just perfect) attendance.", "adaptable_boundaries": ["Recognition form", "Campaign branding"]}]'::jsonb,
  '{"target_group": "All students for prevention (Tier 1); the approximately [X] percent at 10 to 19 percent absence for mentoring (Tier 2); the [number] chronically absent students for case management (Tier 3). Priority attention to [student groups] with disproportionate absence rates under current practice.", "problem_statement": "Too many of our students are missing enough school to derail their learning, and our response begins after the damage is done. Last year [X] percent of students were chronically absent (missing 10 percent or more of enrolled days), with rates of [X] percent for [student group] versus [X] percent for peers. Attendance in the first month is a strong predictor of year-end chronic absence, yet our current process flags students only after [number] unexcused absences and leads with consequence letters rather than relationships. We lack a tiered system that prevents, notices early, and removes the actual barriers keeping students out.", "lagging_indicators": ["Chronic absenteeism rate, disaggregated by student group", "Average daily attendance", "Percent of Tier 2 students returning to satisfactory attendance", "Family survey: school notices and cares when my child is absent"], "leading_indicators": ["Percent of flagged students contacted within 48 hours", "Weekly mentor touchpoint completion rate", "Family outreach contacts logged per week", "First-month attendance rate versus last year"], "measurement_timeline": ["Weekly early-warning review with logged decisions", "Monthly tier-movement analysis (who improved, who slid)", "Quarterly disproportionality check by student group", "Annual comparison against baseline year"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  'd3be9619-27a5-49c6-852d-df808257874f',
  'Family Engagement Partnership',
  'Community',
  'Moves family engagement from events and attendance counts to partnership in learning: structured teacher-family communication, academic partnering tools families can actually use, and family voice in school decisions.',
  'Five decades of research link family engagement to achievement, attendance, and graduation (Henderson and Mapp, 2002, synthesis of 51 studies). The engagement that matters most for adolescents is academic socialization, communicating expectations and connecting school to future goals, rather than event attendance (Hill and Tyson, 2009, meta-analysis). Teacher outreach experiments show brief individualized messages home substantially improve student persistence: a 41 percent reduction in students failing to earn course credit in a credit-recovery program (Kraft and Rogers, 2015); related work links teacher-family communication to homework completion and engagement (Kraft and Dougherty, 2013). Dual-capacity framework (Mapp and Kuttner, 2013) guides building both family and staff capability. References: Henderson and Mapp (2002), A New Wave of Evidence, SEDL. Hill and Tyson (2009), Developmental Psychology meta-analysis. Kraft and Rogers (2015), Economics of Education Review. Mapp and Kuttner (2013), USDOE dual-capacity framework. Evidence level: Strong for the engagement-outcomes link; Moderate for specific school-led strategies.',
  ARRAY['Increase families equipped to support learning at home', 'Improve teacher-family communication quality and frequency', 'Raise family trust and school climate measures', 'Strengthen attendance and homework follow-through']::text[],
  'Full year: communication systems in month 1, academic partnering tools by month 2, family voice structures by semester 2',
  ARRAY['Translation and interpretation for all major home languages', 'Teacher time for positive outreach (protected, not added)', 'Family-friendly academic tools tied to current units', 'Stipends or supports enabling diverse family participation in decision groups']::text[],
  '[{"name": "Positive contact before problem contact", "is_core": true, "look_fors": ["Positive-contact log shows full coverage by [date]", "Contacts are personal, not blast messages"], "description": "Every family receives at least one positive, personal communication from their child''s teacher before any concern is raised.", "adaptable_boundaries": ["Channel and language", "Timing across the first quarter"]}, {"name": "Academic partnering tools in home languages", "is_core": true, "look_fors": ["Tools tied to current units, not generic tips", "Available in major home languages", "Family usage feedback collected"], "description": "Families get concrete, jargon-free tools showing what students are learning now and one way to support it at home.", "adaptable_boundaries": ["Format (paper, text, video)", "Frequency"]}, {"name": "Two-way communication channel", "is_core": true, "look_fors": ["Response-time norm published and met", "Family-initiated contacts tracked and welcomed"], "description": "Families can reach teachers in their language through a known channel with an expected response time; communication flows both directions.", "adaptable_boundaries": ["Platform", "Response-time norm"]}, {"name": "Family voice in decisions", "is_core": false, "look_fors": ["Membership reflects the student population", "At least one decision per semester visibly shaped by family input"], "description": "A representative family group meets regularly with leadership on real decisions, with barriers to participation removed.", "adaptable_boundaries": ["Structure (council, focus groups)", "Meeting logistics"]}, {"name": "Staff capacity building", "is_core": false, "look_fors": ["PD includes family-partnership skills", "Outreach time protected in the schedule"], "description": "Teachers receive training and time for partnership work; engagement quality is part of how the school defines good practice.", "adaptable_boundaries": ["Training source and format"]}]'::jsonb,
  '{"target_group": "All families, with deliberate priority on those least reached by current practice: [multilingual families, families of students in intervention, specific neighborhoods or programs]. Measure reach by group, not just totals.", "problem_statement": "Our family engagement counts attendance at events rather than building partnership in learning, and the families we reach least are the ones whose students need partnership most. Event attendance runs [X] percent and skews toward [groups]; our family survey shows only [X] percent of families feel equipped to support learning at home, dropping to [X] percent among [multilingual families or other groups]. Teacher-family contact is currently [mostly problem-triggered], and [X] percent of communications go home in English only. We lack systems that make academic partnership easy for every family, in their language, around what students are learning right now.", "lagging_indicators": ["Family survey: equipped to support learning, by group", "Family trust and climate measures", "Attendance and homework completion trends", "Event and conference participation, disaggregated"], "leading_indicators": ["Percent of families receiving a positive personal contact by [date]", "Partnering tool distribution and usage by language group", "Two-way channel response-time compliance", "Family advisory participation reflecting school demographics"], "measurement_timeline": ["Monthly outreach coverage review by classroom", "Quarterly family pulse survey in home languages", "Semester reach analysis by family group", "Annual partnership survey and goal reset"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '73cc1bc0-6118-400d-a67d-51f8e08195a1',
  'High-Dosage Tutoring',
  'Intervention',
  'Tutoring delivered the way the evidence says it works: 3 or more sessions weekly, groups of 4 or fewer, during the school day, with a consistent trained tutor using quality materials aligned to classroom instruction.',
  'The strongest intervention evidence base in K-12 education. Meta-analysis of 96 randomized trials finds pooled effects of roughly 0.3 SD (0.37 SD in the 2020 NBER working paper; 0.29 SD in the peer-reviewed version, Nickow, Oreopoulos, and Quan, 2024, American Educational Research Journal), among the largest of any school intervention. Effects are strongest for teacher and paraprofessional tutors, during-school-day delivery, and daily or near-daily frequency. Design principles codified by the National Student Support Accelerator: dosage of 3 or more sessions weekly, 30 plus minutes, groups of 1 to 4, consistent tutor relationships, data-informed sessions. References: Nickow, Oreopoulos, and Quan, NBER working paper 27476 (2020) and American Educational Research Journal (2024). Fryer (2017), Handbook of Field Experiments, on high-dosage tutoring in Houston and Chicago. Robinson, Kraft, Loeb, and Schueler (2021), EdResearch for Recovery design brief. Evidence level: Strong (the design principles are the active ingredients; diluting dosage dilutes effects).',
  ARRAY['Accelerate achievement for students below grade level', 'Close gaps without pulling students from core instruction', 'Build student academic confidence through a consistent adult relationship']::text[],
  'Semester minimum: tutor hiring and training in weeks 1 to 4, sessions running by week 5, dosage and growth review every 6 weeks',
  ARRAY['Tutors (teachers, paraprofessionals, trained community members or college students)', 'Schedule space for 3 to 5 weekly sessions of 30 to 50 minutes during the school day', 'Materials aligned to core curriculum', 'Tutor training and ongoing support (2 to 4 hours monthly)']::text[],
  '[{"name": "Dosage held at 3 plus sessions weekly", "is_core": true, "look_fors": ["Session logs show 3 plus weekly per student", "Missed sessions rescheduled within the week"], "description": "Each student receives at least 3 sessions of 30 or more minutes per week; below this threshold the evidence base no longer applies.", "adaptable_boundaries": ["Session length 30 to 50 minutes", "Time of day within the school day"]}, {"name": "Groups of 4 or fewer with a consistent tutor", "is_core": true, "look_fors": ["Group rosters at 4 or fewer", "Tutor continuity across the semester"], "description": "Small groups keep response rates high; the same tutor builds the relationship that drives engagement.", "adaptable_boundaries": ["1:1 versus small group by need", "Tutor type (teacher, para, trained external)"]}, {"name": "During the school day, not optional after-school", "is_core": true, "look_fors": ["Sessions on the master schedule", "Attendance above 90 percent"], "description": "Sessions are scheduled inside the day so the students who most need tutoring actually receive it.", "adaptable_boundaries": ["Which block hosts tutoring (not core instruction in the same subject)"]}, {"name": "Aligned materials and data-informed sessions", "is_core": false, "look_fors": ["Tutor can name the current classroom topic", "Session plans reference student data"], "description": "Tutoring uses quality materials connected to classroom content, and tutors see student data to target sessions.", "adaptable_boundaries": ["Specific materials", "Data tools"]}, {"name": "Tutor training and support cadence", "is_core": false, "look_fors": ["Training completed before first session", "Monthly support sessions held"], "description": "Tutors get initial training and monthly support on content, relationships, and data use.", "adaptable_boundaries": ["Training provider and format"]}]'::jsonb,
  '{"target_group": "The [number] students in grades [range] scoring below [benchmark threshold] in [subject], prioritized by need. Verify that [student groups] are proportionally served and that pull-out scheduling never costs them core instruction in the same subject.", "problem_statement": "Students who are behind need more instructional time with more individual attention than whole-class teaching can provide, and our current supports are too diluted to move them. [Number] students in grades [range] are below grade level in [subject]; our existing tutoring reaches [X] percent of them, after school, with attendance around [X] percent and rotating tutors. Research is unambiguous that tutoring works at 0.37 SD when dosage, group size, and consistency are protected, and ours protects none of the three. We are running the version of tutoring that does not work.", "lagging_indicators": ["Growth on progress monitoring versus comparison expectations", "Benchmark movement fall to spring for tutored students", "Course grades in the tutored subject", "Student academic confidence survey"], "leading_indicators": ["Average sessions per student per week (target 3 plus)", "Session attendance rate", "Tutor consistency (percent of students keeping the same tutor)", "Group size compliance"], "measurement_timeline": ["Weekly dosage and attendance logs", "Progress monitoring every 2 weeks", "6-week dosage and growth review with regrouping decisions", "Semester effect review against benchmark data"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '92cde9b2-868d-4168-8034-609081db7a5b',
  'Intensive Literacy Intervention',
  'Intervention',
  'High-dosage, small-group or 1:1 intervention focusing on decoding, fluency, and comprehension for students significantly below grade level.',
  'Evidence from targeted intervention studies shows accelerated growth when delivered with sufficient intensity and fidelity. References: Wanzek and Vaughn (2007), synthesis of extensive early reading interventions, School Psychology Review. Scammacca et al. (2007), intervention synthesis for struggling readers. National Center on Intensive Intervention (intensiveintervention.org), data-based individualization framework. Evidence level: Strong for intensive small-group intervention design principles.',
  ARRAY['Accelerate reading growth', 'Close skill gaps', 'Improve comprehension']::text[],
  'Daily 30–45 minute sessions for 12–24 weeks',
  ARRAY['Intervention materials', 'Progress monitoring tools', 'Training & coaching']::text[],
  '[{"name": "Diagnostic placement", "is_core": true, "description": "Pinpoint skill deficits to target instruction."}, {"name": "High-dosage small group", "is_core": true, "description": "Daily sessions with explicit instruction."}, {"name": "Cumulative review & practice", "is_core": true, "description": "Spiral practice to solidify learning."}, {"name": "Frequent progress monitoring", "is_core": true, "description": "Weekly tracking to adjust instruction."}]'::jsonb,
  '{"target_group": "The [number] students in grades [range] scoring more than 1.5 standard deviations below benchmark with inadequate response to prior intervention, reviewed to ensure no student group is over- or under-identified.", "problem_statement": "A small group of students remains far below grade level in reading despite receiving core instruction and standard interventions. Currently [number] students in grades [range] score more than 1.5 standard deviations below benchmark, and [X]% of them have shown flat or declining growth across two or more progress-monitoring cycles. These students need a fundamentally more intensive approach: smaller groups, more minutes, more precise diagnosis of skill gaps, and more frequent progress checks than our current intervention block provides.", "lagging_indicators": ["Rate of improvement versus goal line on progress monitoring", "Percent of students meeting intervention exit criteria", "Benchmark composite movement fall to spring", "Reading self-concept (student survey)"], "leading_indicators": ["Intervention sessions delivered versus scheduled (dosage)", "Group size held at or below [3 to 5] students", "Percent of sessions following the diagnostic-prescriptive plan", "Interventionist-classroom teacher communication touchpoints"], "measurement_timeline": ["Weekly progress monitoring with goal-line analysis", "Intervention plan review every 6 to 8 weeks with intensify-or-exit decisions", "Benchmark screening fall, winter, and spring", "Semester case review with families"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '8b62dd48-8964-422d-b7d7-225fb1bb4c57',
  'MTSS/RTI Framework',
  'Framework',
  'Tiered system providing increasing levels of support matched to student need using screening, progress monitoring, and data-based decision making.',
  'Strong evidence for improved outcomes when high-quality core instruction, screening, and targeted interventions are implemented with fidelity. References: Burns, Appleton, and Stehouwer (2005), meta-analysis of RTI field implementations, Journal of Psychoeducational Assessment. IES Practice Guides on RTI in reading (2009) and mathematics (2009). Evidence level: Strong for tiered prevention logic; implementation quality drives outcomes.',
  ARRAY['Improve universal screening coverage', 'Increase responsiveness to interventions', 'Reduce special education referrals']::text[],
  'Establish within a semester; refine continuously through data cycles',
  ARRAY['Screening tools', 'Progress monitoring probes', 'Intervention menu']::text[],
  '[{"name": "Universal screening", "is_core": true, "description": "At least 3x/year with high coverage."}, {"name": "Tiered intervention menu", "is_core": true, "description": "Evidence-based options matched to need."}, {"name": "Data meetings", "is_core": true, "description": "Regular team review and instructional adjustments."}, {"name": "Progress monitoring", "is_core": true, "description": "Weekly or biweekly measures to track growth."}, {"name": "Check & adjust", "is_core": false, "description": "Fidelity checks and refinements."}]'::jsonb,
  '{"target_group": "All students through universal screening (Tier 1); the approximately [X]% needing supplemental intervention (Tier 2) and [X]% needing intensive support (Tier 3), identified by shared data rules rather than teacher discretion alone.", "problem_statement": "Students who need more than core instruction are identified late, inconsistently, or not at all, and the support they receive depends more on which teacher they have than on their data. Currently [X]% of students receive some intervention, but entry and exit decisions lack shared criteria, intervention quality varies across grades, and [X]% of special education referrals show no documented intervention history. The result is students waiting to fail rather than receiving timely, layered support matched to need.", "lagging_indicators": ["Median student growth percentile, by tier and student group", "Percent of Tier 2 students returning to Tier 1 within a semester", "Special education referral and qualification rates", "Course failure or retention rates"], "leading_indicators": ["Percent of students screened within the screening window", "Percent of intervention groups meeting as scheduled", "Data-meeting attendance and decision-log completion", "Percent of interventions with progress monitoring at the planned frequency"], "measurement_timeline": ["Universal screening three times per year", "Biweekly progress monitoring for Tier 2, weekly for Tier 3", "Grade-level data meetings every 4 to 6 weeks with documented decisions", "Annual MTSS fidelity self-assessment"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  'a631661f-8ea1-4341-baa2-288347ac7ea0',
  'New Teacher Induction & Coaching',
  'Adult Practice',
  'A structured induction system pairing every new teacher with a trained mentor and regular instructional coaching cycles, so early-career teachers build skill and stay, rather than survive and leave.',
  'Reviews of induction research (Ingersoll and Strong, 2011) link comprehensive induction to better retention, instruction, and student achievement. Meta-analysis of instructional coaching (Kraft, Blazar, and Hogan, 2018) finds pooled effects of 0.49 SD on instructional practice and 0.18 SD on achievement. Effects depend on dosage and mentor quality: assigned, trained, same-field mentors with protected time outperform informal buddy systems. References: Ingersoll and Strong (2011), review of induction research, Review of Educational Research. Kraft, Blazar, and Hogan (2018), meta-analysis of 60 coaching studies, Review of Educational Research, 0.49 SD instruction and 0.18 SD achievement. Glazerman et al. (2010), IES randomized induction study, gains by year 3. Evidence level: Strong for coaching; Moderate for comprehensive induction packages.',
  ARRAY['Improve new-teacher retention', 'Accelerate instructional skill in years 1 to 3', 'Reduce variance in student experience across classrooms', 'Build internal mentoring capacity']::text[],
  'Full year minimum: mentor matching before day 1, coaching cycles from week 3, learning community monthly, formal reviews each semester',
  ARRAY['Trained mentors with protected time (release periods or stipends)', 'Coaching cycle time: observation plus debrief every 2 to 3 weeks', 'Monthly new-teacher learning community time', 'Administrator time for non-evaluative check-ins']::text[],
  '[{"name": "Trained, same-field mentor for every new teacher", "is_core": true, "look_fors": ["Match completed before the first student day", "Mentor has documented release time or stipend", "Weekly contact in the first quarter"], "description": "Mentors are selected for skill, trained for the role, matched by subject or grade, and given protected time, not just goodwill.", "adaptable_boundaries": ["Match across buildings when needed", "Stipend versus release structure"]}, {"name": "Observation-feedback coaching cycles", "is_core": true, "look_fors": ["Cycle cadence held all year", "Debrief within 48 hours of observation", "One next move, practiced, not a list of ten"], "description": "Every 2 to 3 weeks: a focused observation against one agreed look-for, then a debrief that names one strength and one next move with rehearsal.", "adaptable_boundaries": ["Who coaches (mentor, instructional coach, peer)", "Observation length and focus areas"]}, {"name": "Non-evaluative status of mentoring", "is_core": true, "look_fors": ["Mentors do not contribute to evaluation ratings", "New teachers raise real struggles in debriefs"], "description": "Mentoring and coaching are firewalled from formal evaluation so new teachers can show real problems safely.", "adaptable_boundaries": ["How the firewall is communicated"]}, {"name": "New-teacher learning community", "is_core": false, "look_fors": ["Sessions are problem-of-practice based, not announcements", "Attendance held by leadership"], "description": "Monthly facilitated sessions where the cohort works on shared problems of practice and builds peer support.", "adaptable_boundaries": ["Topics driven by cohort needs", "Format and timing"]}, {"name": "Leadership check-ins on conditions", "is_core": false, "look_fors": ["Quarterly cadence kept", "At least one named condition improved per semester"], "description": "Administrators meet each new teacher quarterly about workload, support, and belonging, and act on what they hear.", "adaptable_boundaries": ["Format (individual or small group)"]}]'::jsonb,
  '{"target_group": "All teachers in years 1 to 3, beginning with this year''s [number] new hires. Note which student populations are most exposed to early-career classrooms and whether that exposure is equitable across the school or network.", "problem_statement": "We are losing new teachers faster than we can develop them, and students in their classrooms feel the difference. Over the past [number] years, [X] percent of teachers left within their first three years, and exit conversations cite [top reasons: workload, isolation, behavior support]. Our current induction is a [number]-day orientation and an informal buddy, with no protected mentoring time and no coaching cycle; observation data show wider variance in instructional quality in years 1 to 3 classrooms than in any other group. The students most affected are in [schools or grades with highest new-teacher concentration], which serve [X] percent [student group]. We lack a system that develops new teachers deliberately rather than hoping they survive.", "lagging_indicators": ["New-teacher retention at years 1, 2, and 3", "Observed instructional growth on the agreed framework", "Student outcome trends in years 1 to 3 classrooms", "Exit interview themes year over year"], "leading_indicators": ["Percent of new teachers with a trained, matched mentor by day 1", "Coaching cycles completed versus scheduled", "New-teacher reported support and safety (quarterly pulse)", "Mentor protected-time hours actually used"], "measurement_timeline": ["Quarterly new-teacher pulse survey", "Coaching cycle logs reviewed monthly by the implementation team", "Semester instructional growth review", "Annual retention and exposure-equity analysis"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '1c5e8b01-c1e1-4328-862b-9b60dfde92dc',
  'PBIS (Positive Behavioral Interventions and Supports)',
  'Behavior',
  'A multi-tiered framework emphasizing proactive strategies for defining, teaching, and supporting appropriate student behaviors.',
  'Extensive evidence across hundreds of schools showing reductions in office discipline referrals and improvements in climate. References: Bradshaw, Mitchell, and Leaf (2010), randomized trial of school-wide PBIS in 37 elementary schools, Journal of Positive Behavior Interventions. Horner et al. (2009), randomized wait-list trial, JPBI. Center on PBIS (pbis.org), tiered fidelity inventory and evidence reviews. Evidence level: Strong (multiple randomized trials).',
  ARRAY['Reduce office discipline referrals', 'Increase instructional time', 'Improve school climate']::text[],
  'School-wide rollout over 6–12 months with continuous data cycles',
  ARRAY['Behavior matrix posters', 'Acknowledgement system', 'Referral data tracker']::text[],
  '[{"name": "Behavior expectations matrix", "is_core": true, "description": "Define 3\u20135 positively stated expectations across settings."}, {"name": "Explicit teaching of expectations", "is_core": true, "description": "Direct instruction and practice of expected behaviors."}, {"name": "Acknowledgement system", "is_core": true, "description": "Consistent reinforcement of expected behaviors."}, {"name": "Data-based problem solving", "is_core": true, "description": "Monthly review of ODRs to target supports."}, {"name": "Classroom routines & corrections", "is_core": false, "description": "Active supervision, precorrections, and calm responses."}]'::jsonb,
  '{"target_group": "All students school-wide (Tier 1), with Tier 2 supports for the approximately [X]% of students with 2 to 5 referrals. Priority attention to [student groups] who are disproportionately referred under current practice.", "problem_statement": "Office discipline referrals (ODRs) are consuming instructional time and disproportionately affecting some student groups. Last year we logged [number] ODRs, averaging [X] per 100 students per month, with referrals concentrated in [settings such as hallways, cafeteria, transitions]. Students lose an estimated [X] minutes of instruction per referral, and our data show [student group] is referred at [X] times the rate of peers. Reactive discipline has not changed the pattern; we lack a school-wide system that teaches and reinforces expected behavior proactively.", "lagging_indicators": ["ODRs per 100 students per month", "Suspension rate, disaggregated by student group", "Instructional minutes recovered (referrals times average minutes)", "Student and staff school-climate survey scores"], "leading_indicators": ["Percent of staff teaching expectations weekly (walkthrough data)", "Acknowledgment-to-correction ratio (target 4:1)", "Percent of students who can state the school expectations", "Staff consistency in minor versus major referral definitions"], "measurement_timeline": ["Monthly ODR review by the implementation team, disaggregated by location, time, and student group", "Quarterly climate survey pulse (students and staff)", "Semester suspension and disproportionality analysis", "Annual full PBIS tiered fidelity inventory"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '8a636bb6-2728-4043-911c-f31e33390561',
  'Professional Learning Communities (PLCs)',
  'Adult Practice',
  'Teacher teams meet in a disciplined cycle around four questions: what students must learn, how we will know, what we do when they have not learned it, and what we do when they already have. Collaboration becomes collective responsibility for results, not a standing meeting.',
  'Teacher collaboration quality predicts achievement gains (Ronfeldt et al., 2015, analysis of 9,000 teachers in Miami-Dade). PLC participation is associated with improved teaching practice and student achievement when teams focus on student learning evidence (Vescio, Ross, and Adams, 2008, review of 11 studies). Meta-analysis finds professional community is associated with achievement at d = 0.25 (Lomos, Hofman, and Bosker, 2011); the evidence is strongest when teams focus on student work and data. The DuFour model supplies the four-question discipline. References: Ronfeldt et al. (2015), American Educational Research Journal. Vescio, Ross, and Adams (2008), Teaching and Teacher Education. Lomos, Hofman, and Bosker (2011), School Effectiveness and School Improvement. DuFour and Eaker, Learning by Doing. Evidence level: Moderate to Strong; effects depend on whether teams examine student evidence rather than logistics.',
  ARRAY['Improve instructional quality through collective inquiry', 'Reduce between-classroom variance in student outcomes', 'Build shared ownership of all students'' learning', 'Sustain job-embedded professional learning']::text[],
  'Full year: norms and protocols in weeks 1 to 4, full inquiry cycles by month 2, cycle review each semester',
  ARRAY['Protected weekly team time (45 to 60 minutes, master-scheduled)', 'Protocols for examining student work and data', 'Team-developed common formative assessments', 'Facilitation training for team leads']::text[],
  '[{"name": "Protected, scheduled collaborative time", "is_core": true, "look_fors": ["Meetings happen weekly as scheduled", "Time is in the master schedule", "Leadership attends periodically without taking over"], "description": "Teams meet weekly during the contractual day; the time is master-scheduled and defended by leadership, not borrowed from planning.", "adaptable_boundaries": ["Day and duration", "Team configuration (grade, subject, vertical)"]}, {"name": "The four questions drive every cycle", "is_core": true, "look_fors": ["Agenda names which question the team is on", "Cycle produces an instructional response, not just discussion"], "description": "Each inquiry cycle answers: what must students learn, how will we know, what do we do when they have not, what do we do when they already have.", "adaptable_boundaries": ["Cycle length (2 to 6 weeks)", "Content focus"]}, {"name": "Student evidence on the table", "is_core": true, "look_fors": ["Actual student work or data present at the meeting", "Protocol visibly used", "Next instructional move recorded with an owner"], "description": "Teams examine common formative assessment results or student work using a protocol; opinions follow evidence, not the reverse.", "adaptable_boundaries": ["Which protocol", "Assessment format"]}, {"name": "Common formative assessments", "is_core": false, "look_fors": ["Same assessment given across the team", "Results disaggregated by classroom and student group"], "description": "Teams design or adopt short shared checks so results are comparable across classrooms and reteaching is targeted.", "adaptable_boundaries": ["Frequency", "Item formats"]}, {"name": "Collective commitments and norms", "is_core": false, "look_fors": ["Norms visible and referenced when violated", "All voices heard in the meeting"], "description": "Teams write and revisit norms that make honest conversation about results safe, including how disagreement is handled.", "adaptable_boundaries": ["Norm content", "Review cadence"]}]'::jsonb,
  '{"target_group": "All instructional staff organized into [grade-level or course-alike] teams, with first-semester focus on [teams or departments]. Attend to whether teams serving the highest concentrations of [student groups] get equal protected time and facilitation support.", "problem_statement": "Our teachers work hard in isolation, and students get a different quality of instruction depending on whose roster they land on. Outcome variance between same-grade classrooms is [X] points on [assessment], teacher collaboration time is currently consumed by [logistics, announcements, compliance tasks], and our survey shows [X] percent of teachers agree that team meetings improve their instruction. Without a disciplined structure that puts student evidence at the center of teacher collaboration, our improvement depends on individual heroics rather than collective capacity.", "lagging_indicators": ["Between-classroom variance on common assessments", "Common formative assessment results by team and student group", "Teacher retention and collective efficacy measures", "Benchmark outcomes in PLC-active grades"], "leading_indicators": ["Percent of scheduled PLC meetings held with student evidence present", "Cycles completed per team per semester", "Instructional responses documented per cycle", "Teacher survey: our team time improves my instruction"], "measurement_timeline": ["Weekly cycle logs (one line per meeting)", "Monthly leadership review of cycle quality across teams", "Semester variance and outcome analysis", "Annual collective efficacy and practice survey"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '4c806c50-b467-467f-9d11-3224e599e5bc',
  'Responsible AI Integration',
  'Innovation',
  'Brings AI tools into teaching and learning the way an implementation-literate school adopts anything: governance and guardrails first, teacher capability next, a monitored pilot before any scale decision, and equity checks throughout.',
  'An emerging evidence base that demands implementation discipline rather than hype adoption. National guidance frames the opportunity and the guardrails: USDOE Office of Educational Technology (2023), Artificial Intelligence and the Future of Teaching and Learning, and UNESCO (2023), Guidance for Generative AI in Education and Research, both stressing human-in-the-loop use, privacy, and equity of access. The nearest strong evidence comes from what AI tools attempt to replicate: tutoring and feedback (Nickow et al., 2024, roughly 0.3 SD for human tutoring) and formative feedback effects; early studies of AI tutors and teacher co-planning tools show promise but few randomized trials in K-12 to date. Teacher time-use surveys report meaningful planning-time savings with AI assistance, which is a working-conditions outcome worth measuring directly. References: USDOE OET (2023). UNESCO (2023). Nickow, Oreopoulos, and Quan (2024), American Educational Research Journal, for the tutoring benchmark AI tools aim at. Evidence level: Emerging; this template treats the pilot itself as the evidence-generating mechanism, which is exactly what the IMPACT framework is for.',
  ARRAY['Safe, policy-compliant AI use by staff and students', 'Teacher time recovered for high-value work', 'Equitable access to AI literacy and tools across student groups', 'Local evidence on what AI use actually improves before scaling']::text[],
  'Year 1: governance and policy in months 1 to 2, staff AI literacy in months 2 to 4, monitored classroom pilot in semester 2, scale decision at year end',
  ARRAY['AI acceptable-use policy aligned to student privacy law (FERPA, COPPA, state statutes)', 'Vetted tool list with data-privacy review', 'PD time for AI literacy (educators first, then students)', 'Pilot teacher cohort with protected reflection time']::text[],
  '[{"name": "Governance before tools", "is_core": true, "look_fors": ["Policy adopted and communicated", "Every piloted tool passed privacy review", "Family notification in home languages"], "description": "An acceptable-use policy, a vetted tool list, and a data-privacy review exist before any classroom use; students and families are informed in plain language.", "adaptable_boundaries": ["Policy specifics by district counsel", "Tool list contents"]}, {"name": "Human-in-the-loop instruction", "is_core": true, "look_fors": ["Teachers describe review-before-use as routine", "No automated grading of consequential work without human review"], "description": "AI drafts, suggests, or tutors; educators decide. No AI output reaches students or families without professional review, and AI never makes consequential decisions about students.", "adaptable_boundaries": ["Which tasks AI assists (planning, feedback drafts, differentiation)"]}, {"name": "Educator AI literacy before student rollout", "is_core": true, "look_fors": ["PD completion before classroom use", "Teachers can name failure modes and checks"], "description": "Staff learn capabilities, failure modes (hallucination, bias), and prompt practices before students use tools under their guidance.", "adaptable_boundaries": ["PD format and provider", "Pace by department"]}, {"name": "Monitored pilot with defined success metrics", "is_core": true, "look_fors": ["Pilot scope and metrics written before launch", "Data reviewed on schedule", "Scale decision recorded with evidence"], "description": "A bounded cohort pilots specific use cases with baseline and outcome measures (time saved, feedback quality, student work quality) feeding a documented scale decision.", "adaptable_boundaries": ["Use cases piloted", "Cohort size"]}, {"name": "Equity of access and benefit", "is_core": true, "look_fors": ["Access audit completed", "Pilot participation and outcomes disaggregated"], "description": "Track who gets to use the tools and who benefits: device and connectivity access, multilingual usability, and whether AI-assisted supports reach the students who need them most.", "adaptable_boundaries": ["Specific equity measures"]}, {"name": "Academic integrity redesign", "is_core": false, "look_fors": ["Per-assignment AI guidance visible to students", "Integrity conversations are instructional, not just punitive"], "description": "Assessment practices are updated so AI strengthens rather than undermines learning, with clear student guidance on permitted use per task.", "adaptable_boundaries": ["Departmental approaches", "Citation and disclosure conventions"]}]'::jsonb,
  '{"target_group": "Year 1 pilot: [number] volunteer teachers across [departments or grades] and their students, selected to include classrooms serving [student groups]. School-wide governance and AI literacy apply to all staff. Verify pilot access does not concentrate in advantaged classrooms.", "problem_statement": "AI tools are already in our building, in [X] percent of student and staff hands by our survey, without policy, training, or evidence guiding their use. Teachers report spending [X] hours weekly on tasks AI could assist (planning, drafting feedback, differentiation), while our current guidance is [silence, an outright ban, or a one-page memo], which has pushed use underground rather than making it safe and effective. We risk both harms of unmanaged adoption (privacy, integrity, inequitable access) and the opportunity cost of ignoring tools that could return educator time to students. We lack a governed, evidence-generating path from curiosity to a real scale decision.", "lagging_indicators": ["Quality of teacher feedback to students (rubric sample, baseline versus pilot)", "Student work quality in piloted use cases", "Teacher working-conditions and workload survey", "Equity audit: access and benefit by student group"], "leading_indicators": ["Percent of staff completing AI literacy PD", "Pilot tool usage within policy (audit)", "Teacher-reported planning time saved (weekly log)", "Privacy review completion for every tool in use"], "measurement_timeline": ["Weekly pilot-teacher logs (5 minutes)", "Monthly pilot cohort reflection with the implementation team", "Semester baseline-versus-pilot comparison on defined metrics", "Year-end scale, sustain, or stop decision with documented evidence"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '4db07071-643d-49b2-bbec-0136e1558936',
  'Restorative Practices',
  'Behavior',
  'A relational approach to community and conflict: proactive circles build belonging, restorative conferences repair harm, and exclusionary discipline becomes the last resort rather than the default.',
  'The largest randomized trial (Augustine et al., 2018, RAND, 44 Pittsburgh schools) found improved climate, with days lost to suspension falling 36 percent in restorative-practice schools versus 18 percent in comparison schools, with the suspension gap between Black and white students narrowing; academic effects were not positive in the trial, which argues for pairing restorative work with strong instruction rather than substituting for it. A Maine RCT (Acosta et al., 2019) found student-reported improvements tied to implementation quality rather than assignment alone. References: Augustine et al. (2018), Can Restorative Practices Improve School Climate and Curb Suspensions?, RAND Corporation. Acosta et al. (2019), Journal of Youth and Adolescence. Gregory et al. (2016), equity effects in RP classrooms, Journal of Educational and Psychological Consultation. Evidence level: Promising and honest-mixed; climate and suspension effects are credible, academic effects are not established, and implementation quality is decisive.',
  ARRAY['Reduce suspensions and days of lost instruction', 'Narrow discipline disproportionality', 'Strengthen student belonging and adult-student relationships', 'Build conflict-repair capacity in students and staff']::text[],
  'Two-year arc: proactive circles and staff training in year 1, full conferencing and tier integration in year 2',
  ARRAY['Multi-day initial training plus coaching for all staff', 'Circle time in advisory or class schedules', 'Trained conference facilitators (2 plus per building)', 'Alignment work with the existing discipline policy and code of conduct']::text[],
  '[{"name": "Proactive community circles", "is_core": true, "look_fors": ["Circles held on schedule, not only after incidents", "All students speak, not just volunteers"], "description": "Regular circles build relationships before harm happens; restorative responses fail without this relational foundation.", "adaptable_boundaries": ["Frequency and venue (advisory, class meetings)", "Circle topics"]}, {"name": "Restorative conferences for significant harm", "is_core": true, "look_fors": ["Trained facilitator leads", "Repair agreement documented and followed up", "Voluntary participation honored"], "description": "Structured facilitated conferences where those harmed and those responsible agree on repair, replacing or accompanying exclusion where appropriate.", "adaptable_boundaries": ["Which incident types qualify", "Family involvement format"]}, {"name": "Discipline policy alignment", "is_core": true, "look_fors": ["Policy names restorative-first infractions", "Administrators apply it consistently (audit)"], "description": "The code of conduct is revised so restorative responses are the documented first option for defined infractions, with exclusion criteria explicit.", "adaptable_boundaries": ["Infraction categories in scope", "Pace of policy phase-in"]}, {"name": "Staff restorative language practices", "is_core": false, "look_fors": ["Restorative questions heard in walkthroughs", "Staff self-report comfort using the practices"], "description": "Day-to-day affective statements and restorative questions replace public reprimand as the default adult response.", "adaptable_boundaries": ["Scripts and prompts used"]}, {"name": "Disproportionality monitoring", "is_core": true, "look_fors": ["Disaggregated review on the calendar", "Action recorded when gaps persist"], "description": "Discipline data reviewed by student group monthly so the equity promise is checked, not assumed.", "adaptable_boundaries": ["Reporting format"]}]'::jsonb,
  '{"target_group": "All students and staff school-wide for proactive circles (Tier 1); restorative conferences for incidents meeting defined criteria. Explicit monitoring for [student groups] currently over-represented in exclusionary discipline.", "problem_statement": "Exclusionary discipline is costing instruction and falling unevenly on our students without changing behavior. Last year we issued [number] suspensions totaling [number] lost instructional days; [student group] received suspensions at [X] times the rate of peers, and [X] percent of suspended students were suspended more than once, which tells us exclusion is not working even on its own terms. Staff report wanting alternatives but lacking training and time. We lack a relational system that builds community proactively and repairs harm when it happens, integrated with rather than bolted onto our discipline policy.", "lagging_indicators": ["Suspension count and days of lost instruction", "Discipline disproportionality ratios by student group", "Repeat-incident rate after conferences", "Student belonging and climate survey"], "leading_indicators": ["Circles held versus scheduled", "Staff trained and using restorative language (walkthrough data)", "Conferences completed with repair agreements", "Percent of qualifying incidents routed restoratively first"], "measurement_timeline": ["Monthly discipline data review, disaggregated", "Quarterly circle fidelity walkthroughs", "Semester climate pulse", "Annual policy and disproportionality audit"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  'fa46924a-599d-4156-91bd-eaa4817b557f',
  'Second Step Social-Emotional Learning',
  'SEL',
  'A structured SEL curriculum building self-management, relationship skills, and responsible decision-making.',
  'Multiple randomized trials report improvements in prosocial behavior and reductions in problem behavior. References: Durlak et al. (2011), meta-analysis of 213 school SEL programs, Child Development, average achievement effect 0.27 SD. Low et al. (2015), randomized trial of Second Step in 61 schools, Journal of School Psychology. Evidence level: Strong for SEL generally; Moderate for program-specific effects.',
  ARRAY['Increase prosocial behaviors', 'Improve self-regulation', 'Reduce disruptive incidents']::text[],
  'Weekly lessons over 20–30 weeks with embedded practice',
  ARRAY['Lesson kits', 'Family engagement letters', 'Implementation guide']::text[],
  '[{"name": "Weekly explicit SEL lessons", "is_core": true, "description": "Scripted lessons with modeling and practice."}, {"name": "Embedded practice routines", "is_core": true, "description": "Daily prompts to generalize skills."}, {"name": "Reinforcement & reflection", "is_core": true, "description": "Acknowledge use of SEL skills; student reflection."}, {"name": "Family connection", "is_core": false, "description": "Send home practice activities."}]'::jsonb,
  '{"target_group": "All students in grades [range] receive core SEL lessons (Tier 1); students flagged by counselor referral or climate data receive small-group reinforcement. Attend to whether [student groups] access supports proportionally.", "problem_statement": "Students need stronger skills in self-regulation, problem solving, and peer relationships than our current approach builds. Behavior data show [number] peer-conflict incidents last [term], counselor referrals for emotional regulation have risen [X]% since [year], and on our climate survey only [X]% of students agreed that students at this school help each other. Teachers report losing instructional time to low-level conflict and dysregulation, and our SEL instruction is currently left to individual teacher initiative rather than a consistent, evidence-based curriculum.", "lagging_indicators": ["Peer-conflict incident rate", "Counselor referrals for regulation support", "Climate survey items on belonging and peer support", "Classroom instructional time lost to behavior (teacher estimate)"], "leading_indicators": ["Percent of classrooms delivering the weekly lesson as scheduled", "Student use of taught vocabulary and strategies (observation)", "Teacher-reported integration of skills outside lesson time", "Family awareness of monthly SEL focus (newsletter engagement)"], "measurement_timeline": ["Weekly lesson-completion tracking by grade", "Monthly incident-data review by the implementation team", "Climate survey fall and spring", "Semester review of counselor referral patterns"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '7b50257a-cd7b-4bef-a310-e247298fa83b',
  'Structured Literacy Program',
  'Literacy',
  'Systematic, explicit instruction in phonemic awareness, phonics, fluency, vocabulary, and comprehension aligned to the science of reading.',
  'Strong evidence from meta-analyses (e.g., National Reading Panel, IES WWC) showing improved early decoding and long-term reading outcomes. References: National Reading Panel (2000), systematic phonics findings. Foorman et al. (1998), classroom instruction comparison, Journal of Educational Psychology. IES Practice Guide, Foundational Skills to Support Reading for Understanding in K-3 (2016), strong evidence for phonemic awareness and decoding recommendations. Evidence level: Strong.',
  ARRAY['Improve decoding accuracy', 'Increase reading fluency', 'Boost comprehension on grade-level texts']::text[],
  'Core implementation over 12–24 weeks with ongoing progress monitoring',
  ARRAY['Tiered materials set', 'Decodable texts', 'Screeners & progress monitors']::text[],
  '[{"name": "Explicit phonics routines", "is_core": true, "description": "Daily, systematic instruction of sound-spelling patterns with cumulative review."}, {"name": "Phonemic awareness practice", "is_core": true, "description": "Oral blending, segmenting, and manipulation activities."}, {"name": "Decodable text practice", "is_core": true, "description": "Controlled texts aligned to taught patterns for fluency."}, {"name": "Error correction routine", "is_core": true, "description": "Immediate corrective feedback with guided practice."}, {"name": "Vocabulary and background", "is_core": false, "description": "Pre-teach key vocabulary and build knowledge."}]'::jsonb,
  '{"target_group": "All K-2 students for core instruction (Tier 1), with priority intervention for the [number] students below benchmark on universal screening, disaggregated to ensure [student groups] are progressing proportionally.", "problem_statement": "Our youngest readers are not building the decoding and fluency foundation that later comprehension depends on. On the [fall/winter] universal screening, [X]% of K-2 students scored below benchmark in decoding and [X]% in oral reading fluency, against a district expectation of at least 80% at benchmark. The gap is widest for [student group], at [X]% below benchmark versus [X]% for peers. Our current core materials emphasize exposure over explicit, systematic instruction in phonemic awareness and phonics, and teachers report uneven preparation to deliver structured literacy practices.", "lagging_indicators": ["Universal screening composite (DIBELS, Acadience, or district measure)", "Percent at benchmark in decoding, by grade and student group", "Oral reading fluency growth (words correct per minute)", "Percent of intervention students closing to benchmark"], "leading_indicators": ["Percent of literacy blocks following the structured routine (walkthroughs)", "Teacher confidence in explicit phonics instruction (self-report)", "Student engagement during word work (observation)", "Weekly progress-monitoring completion rate"], "measurement_timeline": ["Weekly progress monitoring for intervention students", "Monthly grade-level data meetings on routine fidelity and student response", "Benchmark screening fall, winter, and spring", "Semester disproportionality check across student groups"]}'::jsonb
) ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description,
  evidence_base = EXCLUDED.evidence_base, target_outcomes = EXCLUDED.target_outcomes,
  typical_timeline = EXCLUDED.typical_timeline, resources_needed = EXCLUDED.resources_needed,
  active_ingredients = EXCLUDED.active_ingredients, decision_brief_template = EXCLUDED.decision_brief_template;

INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES (
  '0c20ba67-f890-4777-a5b2-0210545c4b1a',
  'Targeted Math Intervention',
  'Math',
  'Systematic small-group math intervention built on explicit instruction, visual representations, number-line work, and word-problem schema instruction, with weekly progress monitoring and intensify-or-exit decisions.',
  'IES What Works Clearinghouse practice guide, Assisting Students Struggling with Mathematics (2021): strong evidence for systematic instruction, mathematical language, and number lines; moderate to strong evidence for visual representations and timed fluency-building activities. Schema-based instruction trials in the middle grades show moderate to large effects on word-problem solving, including for students with disabilities. References: IES What Works Clearinghouse Practice Guide, Assisting Students Struggling with Mathematics (2021), strong evidence for systematic instruction, mathematical language, and number lines. Gersten et al. (2009), meta-analysis of math interventions, Review of Educational Research. Jitendra et al., multiple randomized trials of schema-based instruction. Evidence level: Strong.',
  ARRAY['Accelerate growth for students below benchmark in math', 'Close the word-problem performance gap', 'Build computational fluency and number sense', 'Reduce math anxiety through structured success']::text[],
  'Semester cycles: diagnostic and grouping in weeks 1 to 2, daily or near-daily 25 to 30 minute sessions, formal review every 6 to 8 weeks',
  ARRAY['Protected intervention block (25 to 30 minutes, 4 to 5 days weekly)', 'Trained interventionist or teacher per group of 3 to 5', 'Diagnostic and progress-monitoring measures', 'Manipulatives, number lines, and visual representation materials']::text[],
  '[{"name": "Explicit, systematic intervention lessons", "is_core": true, "look_fors": ["Teacher models with visible reasoning", "Students practice with feedback the same session", "Lesson follows the planned sequence"], "description": "Every session follows a clear sequence: review, modeling with think-aloud, guided practice, independent practice with immediate feedback.", "adaptable_boundaries": ["Curriculum or program used", "Session time of day"]}, {"name": "Visual representations and number lines", "is_core": true, "look_fors": ["Number line visible and used by students", "Students draw or build before writing equations"], "description": "Concrete and visual models (number lines especially) precede and accompany abstract notation in every new concept.", "adaptable_boundaries": ["Specific manipulatives", "Digital versus physical tools"]}, {"name": "Word-problem schema instruction", "is_core": true, "look_fors": ["Students name the problem type", "Representation drawn before solving", "Math vocabulary used in discussion"], "description": "Students learn to identify problem types and represent their structure before computing, with sentence frames supporting mathematical language.", "adaptable_boundaries": ["Problem contexts adjusted to student interests", "Pacing of new schemas"]}, {"name": "Brief timed fluency building", "is_core": false, "look_fors": ["Daily and brief, not occasional and long", "Students chart their own growth"], "description": "5 minutes per session of motivating, timed practice on previously taught skills, tracking personal growth rather than peer comparison.", "adaptable_boundaries": ["Practice format (games, apps, paper)", "Skills targeted"]}, {"name": "Weekly progress monitoring with decision rules", "is_core": true, "look_fors": ["Data plotted weekly", "Decision rule applied, not just data collected"], "description": "Brief weekly measures plotted against a goal line; 4 data points below the line trigger an intensification decision.", "adaptable_boundaries": ["Measure used", "Meeting where decisions happen"]}]'::jsonb,
  '{"target_group": "The [number] students in grades [range] scoring below the [percentile] on benchmark or showing flat growth across two progress-monitoring cycles, grouped 3 to 5 per interventionist. Review identification to ensure [student groups] are neither over- nor under-represented relative to need.", "problem_statement": "A persistent group of students is falling further behind in mathematics each year, and our current support is not intensive enough to change their trajectory. On the [fall/winter] benchmark, [X] percent of students in grades [range] scored below benchmark, and item analysis shows word problems and number sense as the weakest strands ([X] percent correct versus [X] percent on computation). The gap for [student group] is [X] points and has widened since [year]. Our intervention block currently offers homework help rather than systematic instruction, and no student has exited intervention through documented progress in the past [time period].", "lagging_indicators": ["Rate of improvement versus goal line", "Percent of students meeting exit criteria each cycle", "Benchmark movement fall to spring, by student group", "Word-problem strand performance"], "leading_indicators": ["Intervention dosage: sessions delivered versus scheduled", "Fidelity to the explicit lesson sequence (observation)", "Student use of representations before computation", "Weekly progress-monitoring completion"], "measurement_timeline": ["Weekly progress monitoring plotted against goal lines", "Review every 6 to 8 weeks with intensify, continue, or exit decisions", "Benchmark screening fall, winter, and spring", "Semester disproportionality and exit-rate analysis"]}'::jsonb
